class Kisi:
    def __init__(self, ad):
        self._ad = ad # Özel bir adlandırma kuralı ile iç değişken

    @property
    def ad(self):
        """'ad' özelliğinin getter'ı."""
        print("Ad alınıyor...")
        return self._ad

    @ad.setter
    def ad(self, yeni_ad):
        """'ad' özelliğinin setter'ı."""
        if not isinstance(yeni_ad, str):
            raise TypeError("Ad bir string olmalıdır!")
        if len(yeni_ad.strip()) == 0:
            raise ValueError("Ad boş olamaz!")
        print(f"Ad '{yeni_ad}' olarak ayarlanıyor...")
        self._ad = yeni_ad

    @ad.deleter
    def ad(self):
        """'ad' özelliğinin deleter'ı."""
        print("Ad siliniyor...")
        del self._ad

# Kullanım örneği:
insan = Kisi("Ali")

print(f"Başlangıç adı: {insan.ad}")

insan.ad = "Veli"
print(f"Yeni ad: {insan.ad}")

try:
    insan.ad = 123  # Hatalı tip
except TypeError as e:
    print(f"Hata: {e}")

try:
    insan.ad = ""   # Hatalı değer
except ValueError as e:
    print(f"Hata: {e}")

del insan.ad

try:
    print(insan.ad) # Silindikten sonra erişim hatası
except AttributeError as e:
    print(f"Hata: {e}")

insan.ad = "Ayşe" # Silinen adı tekrar ayarla
print(f"Tekrar ayarlanan ad: {insan.ad}")
